# --- DATA FETCHING (GOOGLE SHEETS) ---
# Your specific Google Sheet Link
SHEET_ID = "1u-q5QybMjh4zHbNGny0wKji_PlUukGtXZmfUFvvyqFg"
SHEET_URL = f"https://docs.google.com/spreadsheets/d/{SHEET_ID}/export?format=csv"

@st.cache_data(ttl=600)
def load_sanj_data():
    try:
        df = pd.read_csv(SHEET_URL)
        return df
    except:
        return pd.DataFrame()

inventory_df = load_sanj_data()

# --- INPUT SECTION ---
with st.container():
    c1, c2 = st.columns(2)
    with c1:
        location_input = st.text_input("📍 LOCATION / COLONY", placeholder="e.g. Nipania, Super Corridor, Kanak Greenpark")
    with c2:
        price_input = st.number_input("💰 CURRENT PRICE (₹/sqft)", min_value=500, value=2881, step=50)

# --- LOGIC ---
if st.button("GENERATE INVESTMENT PROJECTION ↗"):
    if location_input:
        with st.spinner("Analyzing location infrastructure and checking Sanj inventory..."):
            
            # 1. Search Sanj Inventory for Matches
            match = None
            if not inventory_df.empty:
                # Basic fuzzy search in the sheet
                mask = inventory_df.apply(lambda row: location_input.lower() in str(row).lower(), axis=1)
                match = inventory_df[mask].head(1)

            # 2. Display Results
            col_res_left, col_res_right = st.columns([2, 1])
            
            with col_res_left:
                st.subheader(f"Analysis for: {location_input}")
                
                # Check for Sanj Projects nearby
                if match is not None and not match.empty:
                    st.markdown(f"""
                    <div class="project-card">
                        <h3>✅ Sanj Properties Verified Project Found!</h3>
                        <p><strong>Project:</strong> {match.iloc[0, 0] if len(match.columns) > 0 else "N/A"}</p>
                        <p><strong>Status:</strong> Ready for Registry / Development in Progress</p>
                        <p><strong>Benefits:</strong> Strategic Location, High ROI, Near Highway.</p>
                    </div>
                    """, unsafe_allow_html=True)
                else:
                    st.warning("⚠️ No direct Sanj Project match in this exact colony, but checking nearby growth corridors...")
                
                # PRICE PROJECTION (Simulated AI Logic)
                st.write("### 📈 10-Year Price Forecast")
                # Dummy Data for Visualization
                chart_data = pd.DataFrame({
                    'Year': [2021, 2022, 2023, 2024, 2025, 2026, 2027, 2028, 2029, 2030],
                    'Price': [price_input*0.7, price_input*0.8, price_input*0.9, price_input, price_input*1.15, 
                              price_input*1.3, price_input*1.5, price_input*1.75, price_input*2.1, price_input*2.5]
                })
                st.line_chart(chart_data.set_index('Year'))

            with col_res_right:
                st.write("### 🌍 Location Insights")
                # Static Map Link
                map_url = f"https://www.google.com/maps/search/{location_input}+Indore"
                st.markdown(f"[📍 Open Live Satellite Map]({map_url})")
                
                st.info("💡 **Infrastructure Drivers:** Nearby Metro Expansion, Master Plan 2035 corridor, and rising commercial activity.")

            # --- ACTION BUTTONS ---
            st.markdown("### Next Steps")
            a1, a2, a3 = st.columns(3)
            with a1:
                st.link_button("📂 View Live Inventory Sheet", f"https://docs.google.com/spreadsheets/d/{SHEET_ID}")
            with a2:
                # WhatsApp Lead
                wa_msg = f"Hi Sanj Properties, I just analyzed {location_input} at ₹{price_input}/sqft. I want to know about your current projects nearby."
                st.link_button("💬 Ask More via WhatsApp", f"https://wa.me/919039914137?text={wa_msg}")
